promptInjection:
Use the Web Audio API for ALL sound effects. DO NOT embed base64-encoded audio (`data:audio/mpeg;base64,...`) — it produces thousands of bytes of unreliable hallucinated data. The Web Audio API synthesizes clean tones in real time with ~10 lines of JS, plays instantly without download, and works offline.

**SHARED AUDIO CONTEXT** (init lazily on first user interaction — required by browser autoplay policy):
```javascript
let _audioCtx = null;
function getAudioCtx() {
  if (!_audioCtx) _audioCtx = new (window.AudioContext || window.webkitAudioContext)();
  return _audioCtx;
}
```

**BEEP / TICK** (short blip — useful for clicks, ticks, button feedback):
```javascript
function playBeep({freq = 800, duration = 100, volume = 0.3, type = 'sine'} = {}) {
  const ctx = getAudioCtx();
  const osc = ctx.createOscillator();
  const gain = ctx.createGain();
  osc.type = type; // 'sine' | 'square' | 'triangle' | 'sawtooth'
  osc.frequency.setValueAtTime(freq, ctx.currentTime);
  gain.gain.setValueAtTime(volume, ctx.currentTime);
  gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + duration / 1000);
  osc.connect(gain).connect(ctx.destination);
  osc.start(ctx.currentTime);
  osc.stop(ctx.currentTime + duration / 1000);
}
```

**CHIME / DING** (3-note pleasant ding — kitchen timer done, task complete):
```javascript
function playChime() {
  const ctx = getAudioCtx();
  const notes = [523.25, 659.25, 783.99]; // C5, E5, G5 — major triad
  notes.forEach((freq, i) => {
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(freq, ctx.currentTime + i * 0.12);
    gain.gain.setValueAtTime(0, ctx.currentTime + i * 0.12);
    gain.gain.linearRampToValueAtTime(0.4, ctx.currentTime + i * 0.12 + 0.01);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + i * 0.12 + 0.6);
    osc.connect(gain).connect(ctx.destination);
    osc.start(ctx.currentTime + i * 0.12);
    osc.stop(ctx.currentTime + i * 0.12 + 0.6);
  });
}
```

**ALARM / BUZZER** (urgent repeating low tone — wake-up alarm, error):
```javascript
function playAlarm({beats = 5, freq = 440} = {}) {
  const ctx = getAudioCtx();
  for (let i = 0; i < beats; i++) {
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = 'square';
    osc.frequency.setValueAtTime(freq, ctx.currentTime + i * 0.4);
    gain.gain.setValueAtTime(0.3, ctx.currentTime + i * 0.4);
    gain.gain.setValueAtTime(0.3, ctx.currentTime + i * 0.4 + 0.2);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + i * 0.4 + 0.25);
    osc.connect(gain).connect(ctx.destination);
    osc.start(ctx.currentTime + i * 0.4);
    osc.stop(ctx.currentTime + i * 0.4 + 0.25);
  }
}
```

